const body = $json.body;
let subtotal = 0;
const items = body.items.map(item => {
  const total = item.total_price_cents || (item.base_price_cents * item.qty);
  subtotal += total;
  return { ...item, total_price_cents: total };
});
const tax = Math.round(subtotal * 0.0952);
const total = subtotal + tax;
const order_id = 'UTO-' + $now.toFormat('x') + '-' + Math.random().toString(36).substr(2, 5).toUpperCase();

const square_body = JSON.stringify({
  idempotency_key: $now.toFormat('x') + '-' + Math.random().toString(36).substr(2, 9),
  order: {
    location_id: 'J4B6A3X6RYA63',
    reference_id: order_id,
    line_items: items.map(item => ({
      name: item.name,
      quantity: String(item.qty),
      base_price_money: {
        amount: Math.round(item.total_price_cents / item.qty),
        currency: 'USD'
      }
    }))
  }
});

return {
  json: {
    ...$json,
    square_body,
    body: {
      ...body,
      items,
      subtotal_cents: subtotal,
      tax_cents: tax,
      frontend_total_cents: total,
      order_id
    }
  }
};

const computeTotals = $("Compute Totals").first().json;
const squareResponse = $input.first().json;

return {
  json: {
    ...computeTotals,
    payment_link: squareResponse.payment_link,
    order_id: squareResponse.order_id,
    related_resources: squareResponse.related_resources
  }
};

const sqlite3 = require('sqlite3').verbose();
const path = '/Users/philliplowe/.openclaw/workspaces/sol/utopia-deli-revamp/orders.db';
const merged = $("Merge").first().json;
const body = merged.body;
const paymentLink = merged.payment_link || {};

return new Promise((resolve) => {
  const db = new sqlite3.Database(path, (err) => {
    if (err) { resolve({ json: { db_error: err.message } }); return; }
    db.run(
      'INSERT INTO orders (order_id, customer_name, customer_email, customer_phone, customer_city, customer_county, cart_json, subtotal_cents, tax_cents, total_cents, square_payment_link, square_order_id, notes, status) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)',
      [body.order_id, body.customer.name, body.customer.email, body.customer.phone, body.customer.city, body.customer.county, JSON.stringify(body.items), body.subtotal_cents, body.tax_cents, body.frontend_total_cents, paymentLink.url || paymentLink.long_url || '', merged.order_id || '', body.notes || '', 'pending'],
      function(err) {
        if (err) resolve({ json: { db_error: err.message } });
        else resolve({ json: { db_saved: true, db_rowid: this.lastID } });
        db.close();
      }
    );
  });
});

const merged = $("Merge").first().json;
const dbResult = $("Save to SQLite").first().json;
const paymentLink = merged.payment_link || {};
const squareLink = (paymentLink.url || paymentLink.long_url) || '';

return { json: { ok: true, message: 'Order received! Check your email for payment link.', square_link: squareLink, order_id: merged.body.order_id || '', total_cents: merged.body.frontend_total_cents || 0, db_saved: dbResult.db_saved || false } };
